import sys
from functools import lru_cache

def solve():
    input_data = sys.stdin.read().split()
    n = int(input_data[0])
    A = list(map(int, input_data[1:n+1]))

    # dp[l][r][side]: current player wins?
    # side=0: last taken was A[l-1] (or -inf if l==0 and it's initial... need special)
    # side=2: initial state (last=-1, i.e., -infinity)

    @lru_cache(maxsize=None)
    def dp(l, r, last):
        # last is the last value appended (-1 means no constraint... use -1 as sentinel)
        # current player tries to win
        if l > r:
            return False  # no moves, current player loses
        can_left = A[l] > last
        can_right = A[r] > last
        if not can_left and not can_right:
            return False  # current player loses
        # Try both moves, current player wins if any move leads to opponent losing
        if can_left and not dp(l+1, r, A[l]):
            return True
        if can_right and not dp(l, r-1, A[r]):
            return True
        return False

    # But last can be any value - too many states
    # Need to represent last differently
    # last is always A[l-1] or A[r+1] or -inf (initial)
    # So encode: last_type: 0=initial(-inf), 1=A[l-1], 2=A[r+1]

    @lru_cache(maxsize=None)
    def dp2(l, r, last_type):
        if last_type == 0:
            last = -1
        elif last_type == 1:
            last = A[l-1] if l > 0 else -1
        else:
            last = A[r+1] if r < n-1 else -1

        if l > r:
            return False
        can_left = A[l] > last
        can_right = A[r] > last
        if not can_left and not can_right:
            return False
        if can_left and not dp2(l+1, r, 1):
            return True
        if can_right and not dp2(l, r-1, 2):
            return True
        return False

    result = dp2(0, n-1, 0)
    print("Alice" if result else "Bob")

solve()

